try {
const b=$input.first().json?.body??$input.first().json;
const o=b.id?b:(b.order??b);
if(!o.id) throw new Error('Payload sin id de pedido');

const SUPA='https://jtqfxakabthzakmhncrw.supabase.co/rest/v1/pedidos_woo';
const KEY='sb_publishable_Wr-dnT92OLrYWsqhTrr4mw_F88RdJ2p';

const row={
  woo_id:o.id,
  numero:String(o.number),
  fecha:(o.date_paid||o.date_created||'').slice(0,10)||null,
  cliente_nombre:((o.billing?.first_name||'')+' '+(o.billing?.last_name||'')).trim(),
  cliente_email:o.billing?.email||'',
  total:parseFloat(o.total)||0,
  estado:o.status,
  lineas:(o.line_items||[]).map(li=>li.name).join(', ')
};

await $helpers.httpRequest({
  method:'POST',
  url:SUPA+'?on_conflict=woo_id',
  headers:{
    'apikey':KEY,
    'Authorization':'Bearer '+KEY,
    'Content-Type':'application/json',
    'Prefer':'resolution=merge-duplicates'
  },
  body:[row],
  json:true
});

return [{json:{success:true,woo_id:row.woo_id,numero:row.numero,cliente:row.cliente_nombre}}];
} catch(err) {
  return [{json:{success:false,error:err.message}}];
}
